from llama_cloud import LlamaCloud
import os

client = LlamaCloud()
pdf_path = "/home/user/prompted_parse_task/sample.pdf"
with open(pdf_path, "rb") as f:
    file_obj = client.files.create(file=f, purpose="parse")
file_id = file_obj.id

custom_prompt = "test"
processing_options = {
    "auto_mode_configuration": [
        {
            "parsing_conf": {
                "custom_prompt": custom_prompt
            }
        }
    ]
}

job = client.parsing.parse(
    file_id=file_id,
    tier="agentic",
    version="latest",
    expand=["markdown"],
    processing_options=processing_options
)

print(f"Type: {type(job)}")
print(f"Attributes: {dir(job)}")
try:
    print(f"ID: {job.id}")
except:
    print("No .id")
try:
    print(f"Job ID: {job.job_id}")
except:
    print("No .job_id")

